// inferred-not-tested:epub.js 用沙箱 iframe 渲染书页,容器需固定像素高
import ePub from 'https://cdn.jsdelivr.net/npm/epubjs@0.3.93/+esm';
const el = document.getElementById('reader'); el.style.height = (data.height ?? 600) + 'px';
const book = ePub(data.url); // .epub 文件 URL 或 ArrayBuffer
const rendition = book.renderTo(el, { width: '100%', height: data.height ?? 600, flow: data.flow ?? 'paginated', spread: data.spread ?? 'auto', allowScriptedContent: false });
rendition.display(data.startCfi);

